require "spec_helper"
require "crawlberg"
require "json"

RSpec.describe "warc" do
  it "warc_basic_output: Scrape single page with WARC output enabled writes to file" do
    engine_config = {"respect_robots_txt" => false, "warc_output" => "/tmp/crawlberg_test.warc"}
    engine = Crawlberg.create_engine(engine_config.to_json)
    url = "#{ENV.fetch("MOCK_SERVER_URL")}/fixtures/warc_basic_output"
    result = Crawlberg.crawl(engine, url)
    expect(result.pages[0].status_code).to(eq(200))
    expect(result.pages.length).to(eq(1))
  end

  it "warc_multi_page_crawl: Crawl multiple pages with depth=1 and WARC output enabled" do
    engine_config = {"max_depth" => 1, "respect_robots_txt" => false, "warc_output" => "/tmp/crawlberg_crawl.warc"}
    engine = Crawlberg.create_engine(engine_config.to_json)
    url = ENV.fetch("MOCK_SERVER_WARC_MULTI_PAGE_CRAWL", nil) ||
      "#{ENV.fetch("MOCK_SERVER_URL")}/fixtures/warc_multi_page_crawl"
    result = Crawlberg.crawl(engine, url)
    expect(result.pages.length).to(be >= 2)
    expect(result.stayed_on_domain).to(be(true))
  end
end
